1	// Dashboard 托管模式的 proxy 进程管理。
2	//
3	// 当前阶段不把 proxy 安装成系统级 daemon，而是让它跟随 session-dashboard server 生命周期：
4	// - dashboard 启动：如果 settings.json 已由我们注入，则拉起 proxy 子进程
5	// - dashboard 退出：主动 SIGTERM 子进程，避免 Ctrl+C 后 proxy 继续占端口
6	// - setup UI 的启动/停止：操作的也是这个托管子进程，而不是 LaunchAgent/systemd
7	//
8	// 注意：pid/port 文件只是给 CLI 和 UI 的缓存。运行态的事实来源仍然是 /_health 探测；
9	// 因为旧版本曾经出现过进程存在但 pid/port 文件丢失的情况。
10	import { existsSync, readFileSync } from "node:fs";
11	import { join } from "node:path";
12	import { homedir } from "node:os";
13	import { spawn } from "node:child_process";
14	import type { Readable } from "node:stream";
15	import http from "node:http";
16	import { DEFAULT_LISTEN_PORT, PATHS } from "./config";
17	
18	type ManagedStatus = "OK" | "DEGRADED" | "DOWN";
19	
20	export interface ManagedProxyStatus {
21	  injected: boolean;
22	  daemonStatus: ManagedStatus;
23	  statusHint?: string;
24	  pid: number | null;
25	  port: number | null;
26	  health: Record<string, unknown> | null;
27	  managed: boolean;
28	}
29	
30	interface ManagedChild {
31	  pid?: number;
32	  exitCode: number | null;
33	  signalCode: NodeJS.Signals | null;
34	  stdout?: Readable | null;
35	  stderr?: Readable | null;
36	  on(event: "close" | "exit", listener: (code: number | null, signal: NodeJS.Signals | null) => void): void;
37	  on(event: "error", listener: (err: Error) => void): void;
38	  kill(signal?: NodeJS.Signals): boolean;
39	}
40	
41	let proxyChild: ManagedChild | null = null;
42	let adoptedProxyPid: number | null = null;
43	
44	function getRepoRoot(): string {
45	  return join(import.meta.dir, "../../..");
46	}
47	
48	function getDistPath(): string {
49	  return join(import.meta.dir, "dist/start.mjs");
50	}
51	
52	function isChildAlive(child: ManagedChild | null): boolean {
53	  return !!child && child.exitCode === null && child.signalCode === null;
54	}
55	
56	export function readClaudeSettingsEnv(): Record<string, string> {
57	  const settingsPath = join(homedir(), ".claude", "settings.json");
58	  if (!existsSync(settingsPath)) return {};
59	  try {
60	    const settings = JSON.parse(readFileSync(settingsPath, "utf8"));
61	    return settings?.env && typeof settings.env === "object" ? settings.env : {};
62	  } catch {
63	    return {};
64	  }
65	}
66	
67	function parseProxyPort(raw: string | undefined): number | null {
68	  if (!raw) return null;
69	  try {
70	    const url = new URL(raw);
71	    if (url.hostname !== "127.0.0.1" && url.hostname !== "localhost") return null;
72	    const port = Number(url.port || 80);
73	    return Number.isFinite(port) && port > 0 ? port : null;
74	  } catch {
75	    return null;
76	  }
77	}
78	
79	export function getConfiguredProxyPort(): number {
80	  const env = readClaudeSettingsEnv();
81	  if (!hasDashboardProxyMarker(env)) return DEFAULT_LISTEN_PORT;
82	  return parseProxyPort(env.HTTPS_PROXY ?? env.https_proxy) ?? DEFAULT_LISTEN_PORT;
83	}
84	
85	function hasDashboardProxyMarker(env: Record<string, string>): boolean {
86	  return env.NODE_EXTRA_CA_CERTS === PATHS.caCert || env.API_DASHBOARD_PROXY_UPSTREAM !== undefined;
87	}
88	
89	export function isProxyConfigured(): boolean {
90	  const env = readClaudeSettingsEnv();
91	  return hasDashboardProxyMarker(env);
92	}
93	
94	async function ensureBuilt(): Promise<void> {
95	  if (existsSync(getDistPath())) return;
96	  await new Promise<void>((resolve, reject) => {
97	    const child = spawn("bun", ["run", "proxy:build"], {
98	      cwd: getRepoRoot(),
99	      env: process.env,
100	      stdio: "inherit",
101	    }) as unknown as ManagedChild;
102	    child.on("close", (code) => {
103	      if (code === 0) resolve();
104	      else reject(new Error(`proxy:build failed with code ${code}`));
105	    });
106	    child.on("error", reject);
107	  });
108	}
109	
110	function pingHealth(port: number, timeoutMs = 1500): Promise<Record<string, unknown> | null> {
111	  return new Promise((resolve) => {
112	    const req = http.get(`http://127.0.0.1:${port}/_health`, (res) => {
113	      let buf = "";
114	      res.on("data", (chunk) => (buf += chunk));
115	      res.on("end", () => {
116	        try {
117	          resolve(JSON.parse(buf));
118	        } catch {
119	          resolve(null);
120	        }
121	      });
122	    });
123	    const timer = setTimeout(() => {
124	      req.destroy();
125	      resolve(null);
126	    }, timeoutMs);
127	    req.on("close", () => clearTimeout(timer));
128	    req.on("error", () => {
129	      clearTimeout(timer);
130	      resolve(null);
131	    });
132	  });
133	}
134	
135	async function findListeningPid(port: number): Promise<number | null> {
136	  if (process.platform !== "darwin" && process.platform !== "linux") return null;
137	  return new Promise((resolve) => {
138	    const child = spawn("lsof", ["-tiTCP:" + port, "-sTCP:LISTEN"], { stdio: ["ignore", "pipe", "ignore"] }) as unknown as ManagedChild;
139	    let out = "";
140	    child.stdout?.on("data", (chunk) => (out += chunk.toString()));
141	    child.on("close", () => {
142	      const pid = Number(out.trim().split("\n")[0]);
143	      resolve(Number.isFinite(pid) && pid > 0 ? pid : null);
144	    });
145	    child.on("error", () => resolve(null));
146	  });
147	}
148	
149	export async function startManagedProxy(port = getConfiguredProxyPort()): Promise<{ ok: boolean; pid?: number; reason?: string }> {
150	  if (isChildAlive(proxyChild)) {
151	    return { ok: true, pid: proxyChild!.pid };
152	  }
153	
154	  const existingHealth = await pingHealth(port);
155	  if (existingHealth?.ok) {
156	    adoptedProxyPid = typeof existingHealth.pid === "number" ? existingHealth.pid : await findListeningPid(port);
157	    return { ok: true, pid: adoptedProxyPid ?? undefined };
158	  }
159	
160	  await ensureBuilt();
161	  const settingsEnv = readClaudeSettingsEnv();
162	  const childEnv = {
163	    ...process.env,
164	    ...settingsEnv,
165	    API_DASHBOARD_PROXY_MODE: "managed",
166	  };
167	
168	  const child = spawn("node", [getDistPath(), "--port", String(port)], {
169	    cwd: getRepoRoot(),
170	    env: childEnv,
171	    stdio: ["ignore", "pipe", "pipe"],
172	  }) as unknown as ManagedChild;
173	  proxyChild = child;
174	  child.stdout?.on("data", (chunk) => process.stdout.write(`[proxy] ${chunk}`));
175	  child.stderr?.on("data", (chunk) => process.stderr.write(`[proxy] ${chunk}`));
176	  child.on("exit", () => {
177	    if (proxyChild === child) proxyChild = null;
178	  });
179	
180	  await new Promise((resolve) => setTimeout(resolve, 500));
181	  const health = await pingHealth(port);
182	  if (health?.ok) return { ok: true, pid: child.pid };
183	
184	  return { ok: false, pid: child.pid, reason: "proxy 子进程已启动，但 /_health 暂无响应" };
185	}
186	
187	export async function stopManagedProxy(port = getConfiguredProxyPort()): Promise<{ ok: boolean; pid?: number; reason?: string }> {
188	  if (isChildAlive(proxyChild)) {
189	    const pid = proxyChild!.pid;
190	    proxyChild!.kill("SIGTERM");
191	    await new Promise((resolve) => setTimeout(resolve, 500));
192	    return { ok: true, pid };
193	  }
194	
195	  // 兼容旧版本遗留进程：没有被当前 dashboard 持有，但仍占着配置端口。
196	  const pid = adoptedProxyPid ?? await findListeningPid(port);
197	  if (!pid) return { ok: false, reason: "未找到正在监听的 proxy 进程" };
198	  try {
199	    process.kill(pid, "SIGTERM");
200	    adoptedProxyPid = null;
201	    return { ok: true, pid };
202	  } catch (err) {
203	    return { ok: false, pid, reason: (err as Error).message };
204	  }
205	}
206	
207	export async function getManagedProxyStatus(): Promise<ManagedProxyStatus> {
208	  const injected = isProxyConfigured();
209	  const port = getConfiguredProxyPort();
210	  const health = await pingHealth(port);
211	  if (health?.ok && typeof health.pid === "number" && !isChildAlive(proxyChild)) {
212	    adoptedProxyPid = health.pid;
213	  }
214	  const pid = typeof health?.pid === "number"
215	    ? health.pid
216	    : isChildAlive(proxyChild)
217	      ? proxyChild!.pid ?? null
218	      : adoptedProxyPid ?? await findListeningPid(port);
219	
220	  if (health?.ok) {
221	    const managed = health.mode === "managed" || pid === proxyChild?.pid;
222	    return { injected, daemonStatus: "OK", pid, port, health, managed };
223	  }
224	  if (pid) {
225	    return {
226	      injected,
227	      daemonStatus: "DEGRADED",
228	      statusHint: "端口存在监听进程，但 /_health 无响应，可能是旧版 proxy 或非 dashboard 托管进程。",
229	      pid,
230	      port,
231	      health: null,
232	      managed: pid === proxyChild?.pid,
233	    };
234	  }
235	  return { injected, daemonStatus: "DOWN", pid: null, port, health: null, managed: false };
236	}
237	
238	export async function startManagedProxyIfConfigured(): Promise<void> {
239	  if (!isProxyConfigured()) return;
240	  const result = await startManagedProxy();
241	  if (!result.ok) {
242	    console.warn(`[proxy] managed start failed: ${result.reason ?? "unknown"}`);
243	  }
244	}
245	
246	export async function stopManagedProxyIfRunning(): Promise<void> {
247	  if (!isChildAlive(proxyChild) && !adoptedProxyPid && !isProxyConfigured()) return;
248	  await stopManagedProxy();
249	}
250

